-- =====================================================
-- 2. Структурированные критерии перехода shoulder_balloon
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    У протокола 0 measurement-критериев: всё → instructor_check (числовые пороги в label)
--    либо self_report (качественное да/нет, включая боль/сон).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 0 → Фаза 1 (готовность к операции)
  (0, 'prehab_deltoid_lower_trap', 'Пациент демонстрирует изометрию дельтовидной и упражнение на нижнюю трапецию', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (0, 'prehab_understands_balloon', 'Понимает, что баллон не восстанавливает сухожилие, а помогает мышцам работать, пока рассасывается', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Понимаете, что баллон не восстанавливает сухожилие, а помогает мышцам работать, пока рассасывается?', 'Это компенсаторная стратегия, а не сшивание сухожилия', 20::smallint, TRUE),
  (0, 'prehab_sling_technique', 'Обучен технике ношения и снятия слинга', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (0, 'prehab_passive_flexion_kept', 'Пассивное сгибание сохранено на дооперационном уровне', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),

  -- Фаза 1 → Фаза 2 (ранняя защита → возврат амплитуды)
  (1, 'passive_flexion_90_p1', 'Пассивное сгибание не менее 90°', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (1, 'passive_er_30_p1', 'Пассивный поворот руки наружу у тела не менее 30°', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'deltoid_scap_activation_p1', 'Дельтовидная и стабилизаторы лопатки включаются без болезненного вздёргивания плеча', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'night_pain_reduced_p1', 'Боль в покое и ночью уменьшилась по сравнению с первой неделей', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль в покое и ночью уменьшилась по сравнению с первой неделей?', 'Сравните с самыми первыми днями после операции', 40::smallint, TRUE),
  (1, 'no_migration_signs_p1', 'Нет клинических признаков смещения баллона', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  (1, 'self_sling_elbow_p1', 'Самостоятельно снимает/надевает слинг и выполняет упражнения для локтя и кисти', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете сами снять и надеть слинг и выполнять упражнения для локтя и кисти?', 'Оцените по последним нескольким дням', 60::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (возврат амплитуды → динамическое укрепление)
  (2, 'active_flexion_120_p2', 'Активное сгибание не менее 120°', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_flexion_150_p2', 'Пассивное сгибание почти полное (не менее 150°) или как на здоровой стороне', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'no_migration_pattern_p2', 'Нет вздёргивания плеча вверх при активном подъёме руки до 90°', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'ir_er_strength_p2', 'Сила поворотов руки внутрь и наружу у тела полная и безболезненная', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'lift_to_shoulder_p2', 'Поднимает руку до уровня плеча без помощи', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете поднять руку до уровня плеча без помощи?', 'Активно, без поддержки здоровой рукой', 50::smallint, TRUE),
  (2, 'sleep_no_pain_wake_p2', 'Спит без регулярных пробуждений от боли', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Спите без регулярных пробуждений от боли?', 'Оцените по типичной неделе', 60::smallint, FALSE),

  -- Фаза 3 → Фаза 4 (динамическое укрепление → возврат к активности)
  (3, 'active_flexion_140_p3', 'Активное сгибание не менее 140° безболезненно', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'full_active_rom_p3', 'Полная активная подвижность во всех направлениях, равная здоровой стороне', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'no_painful_arc_p3', 'Нет болезненной дуги при активном отведении руки', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'er_ir_functional_p3', 'Сила поворотов руки полная и безболезненная в рабочих положениях', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'adl_no_pain_p3', 'Справляется с бытовыми задачами без значимой боли', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Справляетесь с бытовыми задачами без значимой боли?', 'Одевание, мытьё, бытовые дела', 50::smallint, TRUE),

  -- Фаза 4 → выход (возврат к активности и поддержание)
  (4, 'returned_to_activity_p4', 'Вернулся к привычной активности и желаемому уровню досуга или спорта', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Вернулись к привычной активности и желаемому уровню досуга или спорта?', 'Оцените по последним неделям', 10::smallint, TRUE),
  (4, 'stable_active_lift_p4', 'Стабильный безболезненный активный подъём руки без вздёргивания плеча', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'strength_80pct_p4', 'Сила плеча не менее 80% от здоровой стороны (где достижимо; при неоперабельном разрыве порог индивидуален — очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (4, 'self_home_program_p4', 'Уверенно выполняет домашнюю программу самостоятельно', 'self_report', NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверенно выполняете домашнюю программу самостоятельно?', 'Без напоминаний и подсказок куратора', 40::smallint, TRUE),
  (4, 'knows_red_flags_p4', 'Пациент знает красные флаги и когда обращаться к врачу', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_balloon' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
